### `apps/server/src/services/runtimes/claude-code/sdk-event-mapper.ts`

Add a new branch to handle `prompt_suggestion` messages. Insert after the `rate_limit_event` handler (after line 230) and before the `result` handler:

```typescript
// Handle prompt suggestion messages
if (message.type === 'prompt_suggestion') {
  const suggestions = (message as Record<string, unknown>).suggestions as string[];
  if (Array.isArray(suggestions) && suggestions.length > 0) {
    yield {
      type: 'prompt_suggestion',
      data: { suggestions },
    };
  }
  return;
}
```

Key details:
- The `message.type === 'prompt_suggestion'` check identifies SDK suggestion messages
- Cast through `Record<string, unknown>` because the SDK type does not yet have a first-class `prompt_suggestion` type — treat it as an opaque message shape
- Guard with `Array.isArray(suggestions) && suggestions.length > 0` to avoid forwarding malformed or empty suggestion arrays
- Use `return` after yielding to prevent falling through to subsequent handlers

## Testing

Add tests to `apps/server/src/services/runtimes/claude-code/__tests__/sdk-event-mapper.test.ts`. This file already has a `collectEvents` helper, `makeSession`, and `makeToolState` factory functions. Add a new describe block:

```typescript
describe('sdk-event-mapper prompt_suggestion', () => {
  const session = makeSession();
  const sessionId = 'test-session';
  const toolState = makeToolState();

  /** Verify that prompt suggestions from SDK are forwarded through the event pipeline. */
  it('maps prompt_suggestion SDK message to StreamEvent', async () => {
    const msg = {
      type: 'prompt_suggestion',
      suggestions: ['Run the tests', 'Review the changes'],
    } as unknown as SDKMessage;

    const events = await collectEvents(msg, session, sessionId, toolState);

    expect(events).toHaveLength(1);
    expect(events[0]).toEqual({
      type: 'prompt_suggestion',
      data: { suggestions: ['Run the tests', 'Review the changes'] },
    });
  });

  /** Verify that empty suggestion arrays are not forwarded to avoid unnecessary SSE events. */
  it('does not forward empty suggestions array', async () => {
    const msg = {
      type: 'prompt_suggestion',
      suggestions: [],
    } as unknown as SDKMessage;

    const events = await collectEvents(msg, session, sessionId, toolState);

    expect(events).toHaveLength(0);
  });

  /** Verify that non-array suggestions are not forwarded. */
  it('does not forward non-array suggestions', async () => {
    const msg = {
      type: 'prompt_suggestion',
      suggestions: 'not an array',
    } as unknown as SDKMessage;

    const events = await collectEvents(msg, session, sessionId, toolState);

    expect(events).toHaveLength(0);
  });
});
```

Note: The `SDKMessage` import is already at the top of the test file (`import type { SDKMessage } from '@anthropic-ai/claude-agent-sdk'`). If not present in the existing test, add it — but only within this test file which is inside the ESLint-allowed boundary for SDK imports.

